"use strict";(self.webpackChunkpims_manual=self.webpackChunkpims_manual||[]).push([[69],{5769:(e,t,n)=>{n.r(t),n.d(t,{assets:()=>d,contentTitle:()=>o,default:()=>u,frontMatter:()=>a,metadata:()=>r,toc:()=>c});var s=n(4848),i=n(8453);const a={},o="Curriculum, Assessment, and Instruction",r={id:"curriculum-assessment-instruction",title:"Curriculum, Assessment, and Instruction",description:"Division of Assessment and Accountability (DAA)",source:"@site/docs/curriculum-assessment-instruction.mdx",sourceDirName:".",slug:"/curriculum-assessment-instruction",permalink:"/pimsKB/docs/curriculum-assessment-instruction",draft:!1,unlisted:!1,editUrl:"https://github.com/Bwest8/pimsKB/tree/master/docs/curriculum-assessment-instruction.mdx",tags:[],version:"current",frontMatter:{},sidebar:"docs",previous:{title:"Race, Ethnicity, Gender",permalink:"/pimsKB/docs/race-ethnicity-gender-standards"},next:{title:"Templates",permalink:"/pimsKB/docs/templates/intro"}},d={},c=[{value:"Division of Assessment and Accountability (DAA)",id:"division-of-assessment-and-accountability-daa",level:2},{value:"Authorization",id:"authorization",level:2},{value:"PSSA",id:"pssa",level:2},{value:"Keystone Exams",id:"keystone-exams",level:2},{value:"Attribution Map and PDE Attribution Rules",id:"attribution-map-and-pde-attribution-rules",level:2},{value:"Trainings",id:"trainings",level:2},{value:"Website Access",id:"website-access",level:2},{value:"Contact",id:"contact",level:2}];function l(e){const t={a:"a",h1:"h1",h2:"h2",li:"li",p:"p",strong:"strong",ul:"ul",...(0,i.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(t.h1,{id:"curriculum-assessment-and-instruction",children:"Curriculum, Assessment, and Instruction"}),"\n",(0,s.jsx)(t.h2,{id:"division-of-assessment-and-accountability-daa",children:"Division of Assessment and Accountability (DAA)"}),"\n",(0,s.jsx)(t.p,{children:"Pennsylvania\u2019s accountability system, as required by ESSA, is administered by the PDE Bureau of Curriculum, Assessment, and Instruction. The Division of Assessment and Accountability is responsible for the development, administration, scoring, and reporting of the state's PSSA and Keystone assessments and provides guidance to schools and LEAs on assessment and accountability reporting. The bureau\u2019s other assessment and accountability functions include:"}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:"Evaluating LEA, school, and student progress and reporting school performance for compliance with federal and state requirements;"}),"\n",(0,s.jsx)(t.li,{children:"Developing assessment anchors to better align curricula, instruction, and assessment practices;"}),"\n",(0,s.jsx)(t.li,{children:"Coordinating test development, administration, and reporting; and"}),"\n",(0,s.jsx)(t.li,{children:"Providing technical assistance for statewide and local assessment systems."}),"\n"]}),"\n",(0,s.jsxs)(t.p,{children:["During the 2018-19 school year, Pennsylvania transitioned to a new statewide accountability system aligned to federal ESSA requirements. In Pennsylvania, the Future Ready PA Index is the state\u2019s accountability system. The Future Ready PA Index uses a dashboard model to highlight how schools are performing and making progress on multiple indicators. The reporting system moves beyond a single, summative score to increase transparency around school and student group performance. Future Ready PA Index provides publicly accessible data on academic achievement, academic growth, high school graduation rate, regular attendance (related to chronic absenteeism in ESSA), college and career readiness, and information on English Learner proficiency, among other indicators. Although there are many indicators, the DAA\u2019s focus is on the Statewide Assessment Measures, which include English Language Arts (ELA), math and science for the PSSA and PASA, and the Algebra, Literature and Biology Keystone Exam data across eleven student subgroups. For more information on the Future Ready PA Index, visit the ",(0,s.jsx)(t.a,{href:"http://www.education.pa.gov/",children:"PDE website"}),"."]}),"\n",(0,s.jsx)(t.p,{children:"The DAA will continue to publish building-level data for the purposes of educator evaluation pursuant to Section 1138.1 of the Public School Code."}),"\n",(0,s.jsx)(t.h2,{id:"authorization",children:"Authorization"}),"\n",(0,s.jsx)(t.p,{children:"Chapter 4 (relating to Academic Standards) of Title 22 of the Pennsylvania Code authorizes the reporting of assessment data."}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:"Students must test in state assessments, including the PSSAs, Keystone Exams, or PASAs."}),"\n",(0,s.jsx)(t.li,{children:"Students must take Keystone Exams by the Spring of their grade 11 year."}),"\n"]}),"\n",(0,s.jsx)(t.h2,{id:"pssa",children:"PSSA"}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Pennsylvania System of School Assessment (PSSA)"})," includes assessments in English Language Arts and Mathematics which are taken by students in grades 3, 4, 5, 6, 7 and 8. Students in grades 4 and 8 are administered the Science PSSA. The English Language Arts and Mathematics PSSAs include items that are consistent with the Assessment Anchors/Eligible Content aligned to the Pennsylvania Core Standards in English Language Arts and Mathematics. The Science PSSA includes items that are aligned to the Assessment Anchors/Eligible Content aligned to the Pennsylvania Academic Standards for Science."]}),"\n",(0,s.jsx)(t.h2,{id:"keystone-exams",children:"Keystone Exams"}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Keystone Exams"})," are end-of-course assessments in designated content areas. The Keystone Exams serve two purposes: 1) high school accountability assessments for federal and state purposes, and 2) one part of a system of high school graduation requirements for students beginning with the class of 2021. The Algebra I and Literature Keystone Exams include items written to the Assessment Anchors/Eligible Content aligned to the Pennsylvania Core Standards in Mathematics and English Language Arts. The Biology Keystone Exam includes items written to the Assessment Anchor/Eligible Content aligned to the enhanced Pennsylvania Academic Standards for Science."]}),"\n",(0,s.jsx)(t.h2,{id:"attribution-map-and-pde-attribution-rules",children:"Attribution Map and PDE Attribution Rules"}),"\n",(0,s.jsxs)(t.p,{children:["The Attribution Map and PDE Attribution rules are posted on the Pennsylvania Accountability System website. The Attribution Map describes the school and LEA responsible for ensuring student participation in the state assessment, ordering test materials, and administering the tests. It also explains how PSSA, PASA, and grade 11 Keystone Exam scores and participation will be attributed for accountability purposes. These documents are updated annually. The updated Attribution Map will be posted prior to the Grades 3-8 (PSSA and PASA) and Grade 11 (Keystone) Attribution Windows in DRC\u2019s eDIRECT system. All communication regarding Attributions is communicated by DRC to the Assessment Coordinators in the school or district. Access to the eDIRECT is password protected and determined by the LEA\u2019s Chief Administrative Officer. In order to submit accurate data for the Accountability Internal Snapshots, PIMS Administrators are advised to use the PDE Attribution Rules supplement that is posted along with the Attribution Map on the ",(0,s.jsx)(t.a,{href:"http://www.education.pa.gov/pas",children:"PAS webpage"})," (",(0,s.jsx)(t.a,{href:"http://www.education.pa.gov/pas",children:"www.education.pa.gov/pas"}),")."]}),"\n",(0,s.jsx)(t.h2,{id:"trainings",children:"Trainings"}),"\n",(0,s.jsx)(t.p,{children:"Trainings are posted on the PAS webpage and includes a brief recorded webinar and PowerPoint presentation in advance of the live Q&A. All attendees are expected to have viewed the recorded webinar and PowerPoint prior to attending the live Q&A. All trainings are conducted by the Division of Assessment and Accountability. All trainings are posted on the PAS webpage. Training dates are posted with the PIMS Calendar and email broadcasts are sent to all PIMS Administrators. It is the LEA\u2019s responsibility to update the PIMS Administrators who are designated by the LEA to receive PDE communications regarding trainings. To update the PIMS Administrators\u2019 list, please contact your LEA\u2019s MyPDESuite Local security administrator."}),"\n",(0,s.jsx)(t.h2,{id:"website-access",children:"Website Access"}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.a,{href:"http://www.education.pa.gov/pas",children:"Pennsylvania Accountability Systems"})}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.a,{href:"https://www.education.pa.gov/K-12/Assessment%20and%20Accountability/Pages/default.aspx",children:"Division of Assessment and Accountability"})}),"\n",(0,s.jsx)(t.h2,{id:"contact",children:"Contact"}),"\n",(0,s.jsxs)(t.p,{children:["For questions about the PSSA and Keystone Exams, trainings, attributions, Chapter 4, and Future Ready PA Index, please contact the DAA at ",(0,s.jsx)(t.a,{href:"mailto:ra-pas@pa.gov",children:"ra-pas@pa.gov"}),". All other questions should be directed to the PIMS Application Support Desk at (800.661.2423)."]})]})}function u(e={}){const{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,s.jsx)(t,{...e,children:(0,s.jsx)(l,{...e})}):l(e)}},8453:(e,t,n)=>{n.d(t,{R:()=>o,x:()=>r});var s=n(6540);const i={},a=s.createContext(i);function o(e){const t=s.useContext(a);return s.useMemo((function(){return"function"==typeof e?e(t):{...t,...e}}),[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:o(e.components),s.createElement(a.Provider,{value:t},e.children)}}}]);